impl Solution { pub fn find_and_replace_pattern(words: Vec<String>, pattern: String) -> Vec<String> { words.into_iter().filter(|w| { let (mut black_m1, mut black_m2) = ([0; 256], [0; 256]); w.bytes().zip(pattern.bytes()).all(|(b1, b2)| { if black_m1[b1 as usize] == 0 && black_m2[b2 as usize] == 0 { black_m1[b1 as usize] = b2; black_m2[b2 as usize] = b1; true } else { black_m1[b1 as usize] == b2 && black_m2[b2 as usize] == b1 } }) }).collect() } }